using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using McpServer;

var builder = Host.CreateApplicationBuilder(args);

// Register HttpClient for the weather API via named-client pattern.
// The MCP SDK resolves constructor parameters from the DI container,
// so WeatherTools receives this HttpClient automatically.
builder.Services.AddHttpClient<WeatherTools>(client =>
{
    client.BaseAddress = new Uri("https://api.open-meteo.com");
});

builder.Services
    .AddMcpServer()
    .WithStdioServerTransport()
    .WithToolsFromAssembly();

await builder.Build().RunAsync();

