using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

/// <summary>
/// MCP tools that wrap the Open-Meteo REST API.
/// The SDK instantiates this class per-call via DI, injecting HttpClient.
/// </summary>
[McpServerToolType]
public sealed class WeatherTools(HttpClient httpClient)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { PropertyNameCaseInsensitive = true };

    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        CancellationToken cancellationToken = default)
    {
        var url = $"/v1/forecast?latitude={latitude}&longitude={longitude}"
                + "&current=temperature_2m,wind_speed_10m";

        using var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync(cancellationToken);
        var forecast = JsonSerializer.Deserialize<ForecastResponse>(json, JsonOptions);

        return $"Temperature: {forecast?.Current?.Temperature2m}°C, "
             + $"Wind: {forecast?.Current?.WindSpeed10m} km/h";
    }

    // Minimal DTOs for the Open-Meteo response
    private sealed record ForecastResponse(CurrentWeather? Current);

    private sealed record CurrentWeather(
        double Temperature2m,
        double WindSpeed10m);
}

